const Q_PHYSICS_2011=[{"id": "objective>Physics>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">English</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject i'm doing is Physics. <br/>  <br/> Physics is a fundamental branch of science that explores the nature of matter, energy, force, and motion.</div>", "topic": "INTRODUCTION"}, {"id": "objective>Physics>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A carpenter on top of a roof 20.m high dropped a hammer of mass 1.5kg and <br/> it fell freely to the ground.  <br/> The kinetic energy of the hammer just before hitting the ground is  <br/>  [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">450 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300 J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2011/1.png\" style=\"position:relative;max-width:100%;\"/> <br/> N.B: At the height, the matter possesses potential energy, (P.E) but just as it falls to the ground, it acquires a K.E which is equal to its initial P.E <br/> P.E = K.E (at the ground) <br/> mgh = K.E <br/> (1.5)(10)(20) = K.E <br/> K.E = 300J</div>", "topic": "WORK ENERGY AND POWER : CONSERVATION OF ENERGY"}, {"id": "objective>Physics>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two balls X and Y weighing 5g and 50kg respectively were thrown up vertically at the same time with a velocity of 100ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. How will their positions be one second later?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X and Y will both be 500m from the point of throw</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X and Y will be 500m from each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y will be 500 m ahead of X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X will be 500m ahead of Y</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>+2gs.  V=0,   g = -10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/>  2gs = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  ∴  S =  10,000/20   = 500m.  <br/>  Since the distance covered does not depend on the masses of the bodies, both x and y will be 500m from the point of throw.</div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man standing on a lift that is descending does not feel any weight because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is no gravitational pull on the man in the lift</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the inside of the lift is air tight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the lift is in vacuum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is no reaction from the floor of the lift</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a man is inside a lift that is descending, the weight, W of the man is greater than the reaction from the floor to the lift. <br/> W > R</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above shows two vectors at right angles to each other. The value of the resultant vector is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">13.0 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.0 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0 N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2011/2.png\" style=\"position:relative;max-width:100%;\"/> <br/> Resultant, R <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> (Pythagoras' Theorem) <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 64 + 36 <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 100 <br/> R = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">100&nbsp;</span> = 10.0N</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 2kg moves with a velocity of 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> round a circle of radius 4m.Calculate the centripetal force on the object.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Mass, m = 2kg <br/> Velocity,V = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Radius, r = 4m <br/> Centripetal Force, F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2(10)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2(100)<hr size=\"1\" />4</td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = 50N</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If it takes an object 3s to fall freely to the ground from a certain height, what is the distance covered by the object?  <br/>  [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45 m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Time, t = 3s <br/> Height, h = h <br/> Acceleration due to gravity, g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> N.B: The object does not have any initial velocity, it only falls freely under the influence of gravity. <br/> <img src=\"2011/3.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall;</td><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ut</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">gt<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> → u = 0 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">gt<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10(3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">45m</td></tr></table></div></div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The diagrams above show the positions of a cone.The position which can be described as neutral equilibrium is represented as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Y and X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y and Z</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The position which can be described as neutral equilibrium is represented as Z.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a tube of small radius opened at both ends is placed in a liquid, the liquid will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rise above the liquid level if the liquid does not wet the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain at the same level irrespective of whether the liquid wets the glass or not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall below the liquid level if the liquid wets the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall below the liquid level if the liquid does not wet the glass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is D) fall below the liquid level if the liquid does not wet the glass. <br/>  <br/> This phenomenon is known as capillary action, and it occurs due to the interplay of adhesive and cohesive forces between the liquid molecules and the glass tube. When a liquid wets the glass, the adhesive forces between the liquid molecules and the glass are stronger than the cohesive forces between the liquid molecules themselves. This causes the liquid to rise up the tube, creating a meniscus that curves upwards. <br/>  <br/> However, when the liquid does not wet the glass, the adhesive forces are weaker than the cohesive forces. As a result, the liquid molecules tend to stay together, and the surface tension pulls the liquid down into the tube. This creates a meniscus that curves downwards, and the liquid level inside the tube is lower than the level of the surrounding liquid. <br/>  <br/> Therefore, if a tube of small radius opened at both ends is placed in a liquid, the liquid will fall below the liquid level if the liquid does not wet the glass.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I.Density of the liquid  <br/>  II.Depth below the surface of the liquid.  <br/> III. Surface area of the liquid  <br/>  In which of the statement above will pressure be dependent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure in a fluid at rest is dependent on the density of the fluid and the depth below the surface of the fluid. The surface area of the fluid does not affect the pressure. This is according to Pascal's law which states that a change in pressure at any point in an enclosed fluid at rest is transmitted undiminished to all points in the fluid.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I.  High thermal capacity  <br/>  II.  High sensitivity  <br/> III.  Easy readability  <br/> IV.  Accuracy over a wide range of temperatures <br/>  From the statements above, the qualities of a good thermometer are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The qualities of a good thermometer are II, III and IV.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine is used to lift a load of 20N through a height of 10m.  If the efficiency of the machine is 40%, how much work is done?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300 J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Efficiency, E = 40% <br/> Load, L = 20N <br/> Distance moved by load/height = 10m <br/> Workdone/workdone by effort = ? <br/> Recall:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency,</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Work done on Load <hr size=\"1\" />Work done by Effort </td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20×10<hr size=\"1\" />W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">E</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">E</span></td></tr></table></div> <br/> 200 = 0.4 × W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">E</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">E</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />0.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500J</td></tr></table></div></div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following could be effectively used to reduce friction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Petrol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kerosene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Friction can be reduced by using a lubricant. A lubricant is a substance that is introduced to reduce friction between surfaces in mutual contact, which ultimately reduces the heat generated when the surfaces move. It may also have the function of transmitting forces, transporting foreign particles, or heating or cooling the surfaces. In the given options, grease is a lubricant and hence it can be effectively used to reduce friction.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A coper wire was subjected to a tensile stress of 7.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. <br/> Calculate the tensile strain of the wire.  <br/>  [Young modulus = 1.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Young modulus, E =  (tensile stress)/(tensile strain) ;  <br/>  1.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span> N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> =   7.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> / e  <br/>  ∴  e =  (7.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>)/(1.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span> )   = 7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>.   </div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object weighs 22kg in water an 30kg in air.What is the upthrust exerted by the liquid on the object?  <br/>  [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">80 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">520 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">220 N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Weight of the object in water, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</span> = 22kg = 220N <br/> N.B: W = mg ----------------- (i) <br/> g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Weight of the object in air, W = 30kg = 300N <br/> Upthrust = ? <br/> Recall: According to Archimedes principle, upthrust is equal to the loss of weight of a body <br/> U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</span> = W - W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</span> <br/> U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</span> = 300N - 220N = 80N</div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block of aluminium is heated electrically by a 30 W heater. If the temperature rises by 10°C in 5minutes, the heat capacity of the aluminium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">900 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Power, P = 30W <br/> Temperature rise, Δθ = 10°C <br/> Time, t = 5 minutes = 300s <br/> Heat capacity, H = Unknown <br/> Recall: <br/> (1) H = mc <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(2)</td><td style=\"text-align:center;\">c</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Q<hr size=\"1\" />mΔθ</td></tr></table></div> <br/> substitute for (2) in (1) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">Q<hr size=\"1\" />mΔθ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Q<hr size=\"1\" />Δθ</td><td style=\"text-align:center;\">--------------------- (3)</td></tr></table></div> <br/> N.B: Q = Heat energy <br/> Q = Power × Time <br/> N.B: Energy (any form) = Power × Time <br/> Q = 30 × 300s = 9000J <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">From</td><td style=\"text-align:center;\">(3),</td><td style=\"text-align:center;\">H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9000<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">900JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect emitter or absorber of radiant energy is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">red body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">white body</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect emitter or absorber of radiant energy is known as a black body. A black body absorbs all incident radiation, regardless of frequency or angle of incidence. A white body reflects all incident light and therefore is not a perfect absorber, while a red body and a conductor do not have the properties of a perfect emitter or absorber. Therefore, the correct option is 3.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon that shows that increase in pressure lowers the melting point can be observed in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">regelation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coagulation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon that shows that increase in pressure lowers the melting point can be observed in 'regelation'.</div>", "topic": "CHANGE OF STATE : EFFECT OF PRESSURE AND IMPURITIES ON BOILING AND MELTING POINTS"}, {"id": "objective>Physics>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the volume of a gas increases steadily as the temperature increases at constant pressure, the gas obeys</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Charles' law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Graham's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Boyle's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure law</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Charles' law states that the volume of a gas increases steadily as the temperature increases at constant pressure. This is because the kinetic energy of the gas molecules increases with temperature, causing them to move faster and occupy a larger volume.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Steam burn is more severe than that of boiling water because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steam burn is dependent on relative humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steam burn is independent of relative humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steam possess greater heat energy per unit mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water boils at a higher temperature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Steam burn is more severe than that of a building with because steam possesses greater heat energy per unit-mass.</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following types of waves needs a medium for propagation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sound waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Light waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radio waves</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sound waves are mechanical waves and they require a medium (like air, water, or a solid substance) to travel through. These waves are created by the vibration of an object, which causes the air surrounding it to vibrate. The vibrating air then causes the human eardrum to vibrate, which the brain interprets as sound. In contrast, electromagnetic waves (like X-rays, light waves, and radio waves) do not require a medium and can travel through the vacuum of space.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ground is always cold at night because the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">atmosphere reflects the sun's energy at night</div>", "<div style=\"font-family:Cambria;font-size:17px;\">atmosphere absorbs the sun's energy at night</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earth radiates heat to the atmosphere at night</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sun no longer shines at night</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ground is always cold at night because the earth radiates heat to the atmosphere at night. During the day, the sun heats the earth. At night, the earth's surface cools down by radiating its heat into space. This is known as radiative cooling. The atmosphere does not absorb or reflect the sun's energy at night because the sun is not shining on that part of the earth.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal of volume 40cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is heated from 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C to 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C, the increase in <br/> volume is? .....  <br/>  [Linear expansivity of the metal = 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.40cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.14cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Volume: V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 40cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Initial temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 30°C <br/> Final temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 90°C <br/> Linear expansivity, α = 2.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Increase in volume, ΔV = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Volume</td><td style=\"text-align:center;\">expansivity,</td><td style=\"text-align:center;\">γ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Δ<hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">γ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3(2.0</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔV<hr size=\"1\" />40(60)</td></tr></table></div> <br/> ΔV = 6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> × 2400 <br/> ΔV = 144 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> ΔV = 0.144cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I.Change of state  <br/>  II.Diffusion  <br/>  III. Radiation  <br/>  IV.Osmosis  <br/> Which of the processes above can be explained using the kinetic theory?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I, II, IV  can be explained using the kinetic theory.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the human eye looses its power of accommodation, the defect is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">long-sightedness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short-sightedness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presbyopia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">astigmatism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Presbyopia is the gradual loss of your eyes' ability to focus on nearby objects. It's a natural, often annoying part of aging. Presbyopia usually becomes noticeable in your early to mid-40s and continues to worsen until around age 65. Therefore, the correct answer is presbyopia.</div>", "topic": "OPTICAL INSTRUMENTS : SIGHT DEFECTS AND THEIR CORRECTIONS"}, {"id": "objective>Physics>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A length of wire has a frequency of 255Hz when stretched by a force of 225 N. <br/> If the force increases to 324 N,what is the new frequency of vibration?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">356 Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">306 Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">512 Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">488 Hz</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Frequency (Initial), F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 255Hz <br/> Force, F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 225N <br/> Force (Final) = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 324N <br/> Frequency (Final), F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> N.B: To avoid confusion in terms of the letters we have used to denote the parameters, let force, F be described as tension T since tension is a force  <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 255N <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 324N <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 255Hz <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> Recall:  <br/> F α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> F = k&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">255<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">225&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">324&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">255<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />18</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">17</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />18</td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 18 × 17 = 306Hz</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : OVERTONES PRODUCED BY VIBRATING STRINGS AND THEIR COLUMNS"}, {"id": "objective>Physics>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A certain far-sighted person cannot see objects that are closer to the eye than 50cm clearly. Determine the power of the converging lens which will enable him to see at 25cm.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.04 D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.06 D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.02 D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.03 D</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">.</td><td style=\"text-align:center;\">1<hr size=\"1\" />F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />50</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1+2<hr size=\"1\" />50</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />50,</td><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Power</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />f</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />50</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.06</td></tr></table></div></div>", "topic": "OPTICAL INSTRUMENTS : NEAR AND FAR POINTS~~OPTICAL INSTRUMENTS : POWER OF A LENS"}, {"id": "objective>Physics>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following electromagnetic waves has the highest frequency?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ultra-violet rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radio waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Infrared- ays</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The frequency of electromagnetic waves is inversely proportional to their wavelength. Among the given options, X-rays have the shortest wavelength and therefore the highest frequency.</div>", "topic": "ELECTROMAGNETIC SPECTRUM"}, {"id": "objective>Physics>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a red rose flower is observed in blue light, what colour does the <br/> observer see?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magenta</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a red rose is illuminated by blue light, the red pigment in the rose absorbs the blue light, but reflects the red light. However, because the blue light is also present, it mixes with the reflected red light, creating the perception of magenta.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The eclipse of the sun occurs when the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moon's umbra falls on some part of the earth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moon is between the sun and the earth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earth is between the sun and the moon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moon is not completely hidden in the earth's shadow</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solar eclipse occurs when the moon gets between Earth and the sun, and the moon casts a shadow over Earth. This means the moon is between the sun and the earth.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cannon is fired from town X. After how long is the sound heard at a town <br/> Y 4.95 km away?  <br/>  [velocity of sound in air = 333 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15 s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This question tests the concept of echo. Note that when a sound is produced; and the cound encounters a barrier, it will reflect in the opposite direction <br/> <img src=\"2011/4.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N.B:</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">d<hr size=\"1\" />t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x+x<hr size=\"1\" />t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2x<hr size=\"1\" />t</td><td style=\"text-align:center;\">------------------</td><td style=\"text-align:center;\">(i)</td></tr></table></div> <br/> N.B: The question does not say after how long will the echo of the sound be heard at X, it says after how long will it be the sound be heard at Y <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />t</td><td style=\"text-align:center;\">---------------------</td><td style=\"text-align:center;\">(ii)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">333</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4950<hr size=\"1\" />t</td></tr></table></div> <br/> t = 15s</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An image in a convex lens is upright magnified 3 times. If the focal length of the lens is 15cm, what is the object distance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">26cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u;</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-3u</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />15</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />3u</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(3-1)<hr size=\"1\" />3u</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />15</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">3u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30;</td><td style=\"text-align:center;\">u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10cm</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : LINEAR MAGNIFICATION"}, {"id": "objective>Physics>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capacitance of a parallel plate capacitor is 20 μF in air and 60 μF in the presence of a dielectric. What is the dielectric constant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capacitance,  C = (E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> A)/d   <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>   = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  <br/>  20/1  = 60/E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 60/20  = 3. </div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the circuit above, three resistors, 2Ω, 4Ω and 12 Ω are connected in parallel and a 12 V battery disconnected across the combination. The current flowing through the 12Ω resistor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9.6 A      </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 14.4 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2 A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the same voltage is present across the combination. Current through 12Ω  =  12v/12Ω  = 1A  </div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the charge of electricity per kWh is N4, what is the cost of operating an electrical appliance rated 2.50 V, 2A for 6 hours?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N24</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N0.12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N16</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Voltage, V = 2.50v <br/> Current, I = 2A <br/> Time, t = 6 hours  <br/> 1Kwh = ₦4 <br/> Recall: Energy, E = Power (P) × Time (t) --------------------- (i) <br/> P = IV (Electrical Power) <br/> E = IVt ----------------- (2) <br/> E = 2(2.5)6 <br/> E = 5.0 × 6 = 30Wh <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Convert</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">kWh,</td><td style=\"text-align:center;\">30<hr size=\"1\" />1000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.03kWh</td></tr></table></div> <br/> 1kWh = ₦4 <br/> 0.0kWh = x <br/> x = ₦0.12 <br/> </div>", "topic": "ELECTRICAL ENERGY AND POWER : COMMERCIAL UNIT OF ELECTRIC ENERGY AND POWER"}, {"id": "objective>Physics>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct expression for the potential at a point, distance r from a <br/> charge q, in an electric field is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">q<hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4π∈<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\"></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4π∈<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">q<hr size=\"1\" />4π∈<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\"></td></tr></table></div></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The potential at a point, distance r from a charge q, in an electric field is given by the formula V = q / (4πε0r), where ε0 is the permittivity of free space. This formula is derived from Coulomb's law, which states that the force between two charges is directly proportional to the product of their charges and inversely proportional to the square of the distance between them. The potential is the work done per unit charge in bringing a positive test charge from infinity to that point in the field. Therefore, the correct option is the first one.</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three similar cells each of e.m.f 2V and internal resistance 2 Ω are <br/> connected in parallel, the total e.m.f and total internal resistance are <br/> respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6 V, 0.7 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6 V, 6.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 V, 0.7 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 V, 6.0Ω</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2011/5.png\" style=\"position:relative;max-width:100%;\"/> <br/> Total E.m.f = E.m.f of each cell (since they are in parallel <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 2.0V <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Total</td><td style=\"text-align:center;\">resistance,</td><td style=\"text-align:center;\">re</td><td style=\"text-align:center;\">:</td><td style=\"text-align:center;\">1<hr size=\"1\" />re</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />re</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">re</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.67Ω</td></tr></table></div> <br/> ∴ E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 2V, <br/> r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> ≈ 0.7Ω <br/> </div>", "topic": "ELECTRIC CELLS : ARRANGEMENT OF CELLS"}, {"id": "objective>Physics>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In homes, electrical appliances and lamps are connected in parallel because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less voltage will be used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parallel connection does not heat up the wires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independent switches can be used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less current will be used</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is \"independent switches can be used\". <br/>  <br/> Here's why: <br/>  <br/> Independent Switches: In a parallel circuit, each appliance or lamp has its own independent path to the power source. This means that each device can be turned on or off independently using its own switch, without affecting the other devices in the circuit. This is a crucial advantage for home wiring. <br/>  <br/> Let's look at why the other options are incorrect: <br/>  <br/> Parallel connections do not heat up the wires: Both parallel and series connections can heat up wires if the current is too high. The amount of heat generated depends on the current and the wire's resistance. <br/>  <br/> Less current will be used: While the total current in a parallel circuit is the sum of the currents in each branch, each individual device draws the current it needs to operate, not less. <br/>  <br/> Less voltage will be used: In a parallel circuit, each appliance receives the full voltage of the power source, not less.</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two resistors 5 Ω and 10 Ω are arranged first in series and later in <br/> parallel to a 24 V source. The ratio of total power dissipated in the series <br/> and parallel arrangement respectively is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3:5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">none of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> Case 1 <br/> <img src=\"2011/7.png\" style=\"position:relative;max-width:100%;\"/> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 5Ω + 10Ω = 15Ω (series connection) <br/> V = 24V <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Power,</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R</td><td style=\"text-align:center;\">(Electrical</td><td style=\"text-align:center;\">Power)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(24)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">576<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">192<hr size=\"1\" />5</td><td style=\"text-align:center;\">W</td></tr></table></div> <br/>  <br/> Case 2 <br/> <img src=\"2011/8.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />5</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">(Parallel</td><td style=\"text-align:center;\">connection)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 + 1<hr size=\"1\" />10</td></tr></table></div> <br/> 10 = 3R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />3</td><td style=\"text-align:center;\">Ω</td></tr></table></div> <br/> V = 24 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Power,</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(24)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">10<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">576</td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">10<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">576</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3<hr size=\"1\" />10</td><td style=\"text-align:center;\">W</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Ratio</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">Power:</td><td style=\"text-align:center;\">576<hr size=\"1\" />15</td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">576<hr size=\"1\" />10</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">576<hr size=\"1\" />15</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<hr size=\"1\" />576 × 3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Ratio</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />45</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />9</td></tr></table></div></div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will be applied when a metal Y is used to electroplate another metal X in electrolysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Y is the anode and very high current is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X is the anode and very high current is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X is the cathode and Y is the anode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y is the cathode and X is the anode</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In electroplating, the metal to be plated (X) is made the cathode (negative electrode) and the metal to be used for plating (Y) is made the anode (positive electrode). The metal ions from the anode (Y) are oxidized and they move towards the cathode (X) where they are reduced and get deposited. Hence, 'X is the cathode and Y is the anode' is the correct answer.</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radioactive isotope has a decay constant of 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Calculate its half life.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>s</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">T½  = 0.693/⋋ where ⋋ = decay constant   <br/> ∴ T½  = 0.693/(10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>) = 6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> S </div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a property of steel?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It can easily be magnetized and demagnetized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It cannot retain its magnetism longer than iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can be used for making temporary magnets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can be used for making permanent magnets</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A property of steel is that it can be used in making permanent magnets. \t</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the threshold frequency for tungsten is 1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span>Hz, what is its <br/> work function?  <br/>  [h = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.85 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-18</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.58 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.58 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.58 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span>J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The work function of a material is given by the equation Work function = h * threshold frequency. Substituting the given values, we get Work function = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js * 1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span>Hz = 8.58 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J.</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC EMISSIONS"}, {"id": "objective>Physics>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an a.c. circuit, the ratio of r.m.s value to peak value of current is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">√ 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />√ 2</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">In</td><td style=\"text-align:center;\">an</td><td style=\"text-align:center;\">a.c.</td><td style=\"text-align:center;\">circuit,</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rms</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">ratio</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">r.m.s</td><td style=\"text-align:center;\">value</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">peak</td><td style=\"text-align:center;\">value</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">current</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></td></tr></table></div>\t</div>", "topic": "SIMPLE A. C. CIRCUITS : PEAK AND R.M.S. VALUES"}, {"id": "objective>Physics>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two inductors of inductances 4H and 8H are arranged in series and a current of 10A is passed through them. What is the energy stored in them?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">250 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">133 J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy stored in an inductor is given by the equation Energy = 1/2 * L * I^2. For two inductors in series, the total inductance L is the sum of the individual inductances. Substituting the given values, we get Energy = 1/2 * (4H + 8H) * (10A)^2 = 600J.</div>", "topic": "ELECTROMAGNETIC INDUCTION : ENERGY STORED IN AN INDUCTOR"}, {"id": "objective>Physics>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under which of the following conditions do gasses conduct electricity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High pressure and high p.d</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low pressure and low p.d</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low pressure and high p.d</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High pressure and low p.d</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gases conduct electricity under conditions of low pressure and high potential difference (p.d). This is because at low pressure, the atoms of the gas are far apart, making it easier for the electrons to move and conduct electricity. High potential difference provides the necessary energy to ionize the gas atoms, creating free electrons for conduction.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In measuring high frequency a.c., the instrument used is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hot wire ammeter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">d.c. ammeter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moving coil ammeter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moving iron ammeter</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The deflection of a moving iron meter is proportional to the square of the current. Consequently, such meters would normally have a nonlinear scale, but the iron parts are usually modified in shape to make the scale fairly linear over most of its range. Moving iron instruments indicate the RMS value of any AC waveform applied. Moving iron ammeters are commonly used to measure current in industrial frequency AC circuits.</div>", "topic": "MAGNETIC FIELD : MOVING COIL AND MOVING IRON INSTRUMENTS"}, {"id": "objective>Physics>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bond between silicon and germanium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrovalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dative</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bond between silicon and germanium is covalent. Both silicon and germanium are semiconductors and belong to the same group (Group 14) in the periodic table. They have four valence electrons and form covalent bonds by sharing these electrons with other atoms.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following materials has an increase in resistance with temperature</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electrolyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wood</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metals have a positive temperature coefficient of resistance, meaning their resistance increases with an increase in temperature. This is because as temperature increases, the metal ions in the lattice structure of the metal vibrate more vigorously, which increases the number of collisions with the free electrons and hence increases the resistance.</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrical properties of germanium can be altered drastically by the addition of impurities.  The process is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">doping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saturation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amplification</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of altering the electrical properties of a semi conductor material by the addition of impurity is referred to as doping. </div>", "topic": "INTRODUCTORY ELECTRONICS : INTRINSIC AND EXTRINSIC SEMI-CONDUCTORS"}];
